qry:select.qry:xquery:
for $r in SQL('
SELECT LIQ96_CONCEPTOS.c_concepto as c_concepto, max(LIQ96_CONCEPTOS.d_concepto ) as d_concepto, max(LIQ12_TIPOS_CONC.d_tipo_concepto) as tipo, max(LIQ12_TIPOS_CONC.c_tipo_concepto) as c_tipo_concepto FROM LIQ19_EJECUCIONES, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, LIQ20_CONC_LIQ_PER, LIQ96_CONCEPTOS, LIQ12_TIPOS_CONC, LIQ14_CONCEPTOS JOIN LIQ19_EJECUCIONES.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo, LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ99_RECIBOS.oi_liquidacion_ddo, LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_TOT_LIQ_PER.oi_tot_liq_per, LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per, LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo, LIQ96_CONCEPTOS.c_tipo_concepto INNER LIQ12_TIPOS_CONC.c_tipo_concepto, LIQ96_CONCEPTOS.c_concepto INNER LIQ14_CONCEPTOS.c_concepto WHERE LIQ20_CONC_LIQ_PER.n_valor != 0.0 AND LIQ99_LIQUIDACION.c_estado = \'F\' AND LIQ19_EJECUCIONES.oi_liquidacion in ({%=#LIQUIDACIONES:ROW/@values %}) {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND LIQ12_TIPOS_CONC.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (#CONCEPTOSFILTRO:ROW/@id!='') {% AND LIQ14_CONCEPTOS.oi_concepto in ({%=#CONCEPTOSFILTRO:ROW/@id %}) %} {% %} %}
{%? (#PARAMIN:@cod_desde!='') {% AND LIQ96_CONCEPTOS.c_concepto >= {#PARAMIN:@cod_desde} %} {% %} %} {%? (#PARAMIN:@cod_hasta!='') {% AND LIQ96_CONCEPTOS.c_concepto <= {#PARAMIN:@cod_hasta} %} {% %} %}
GROUP BY LIQ96_CONCEPTOS.c_concepto order by c_tipo_concepto asc, c_concepto asc
')/ROWS/ROW

for $r in sql(' SELECT LIQ96_CONCEPTOS.c_concepto, liq99_liquidacion.e_periodo, max(LIQ96_CONCEPTOS.d_concepto) as d_concepto, sum(LIQ20_CONC_LIQ_PER.n_valor) as n_valor FROM LIQ19_EJECUCIONES, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, LIQ20_CONC_LIQ_PER, LIQ96_CONCEPTOS, LIQ12_TIPOS_CONC, LIQ25_PERSONAL_LIQ, PER02_PERSONAL_emp, LIQ14_CONCEPTOS JOIN LIQ19_EJECUCIONES.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo, LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ99_RECIBOS.oi_liquidacion_ddo, LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_TOT_LIQ_PER.oi_tot_liq_per, LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per, LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo, LIQ96_CONCEPTOS.c_tipo_concepto INNER LIQ12_TIPOS_CONC.c_tipo_concepto, LIQ19_EJECUCIONES.oi_liquidacion INNER LIQ25_PERSONAL_LIQ.oi_liquidacion, LIQ25_PERSONAL_LIQ.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, LIQ99_RECIBOS.e_numero_legajo INNER PER02_PERSONAL_EMP.e_numero_legajo, LIQ96_CONCEPTOS.c_concepto INNER LIQ14_CONCEPTOS.c_concepto WHERE LIQ20_CONC_LIQ_PER.n_valor != 0.0 AND LIQ99_LIQUIDACION.c_estado = \'F\' AND LIQ19_EJECUCIONES.oi_liquidacion in ({%=#LIQUIDACIONES:ROW/@values %}) and LIQ25_PERSONAL_LIQ.oi_personal_emp in ({%=#SOURCE:@value %}) {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND LIQ12_TIPOS_CONC.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (#CONCEPTOSFILTRO:ROW/@id!='') {% AND LIQ14_CONCEPTOS.oi_concepto in ({%=#CONCEPTOSFILTRO:ROW/@id %}) %} {% %} %}
{%? (#PARAMIN:@cod_desde!='') {% AND LIQ96_CONCEPTOS.c_concepto >= {#PARAMIN:@cod_desde} %} {% %} %} {%? (#PARAMIN:@cod_hasta!='') {% AND LIQ96_CONCEPTOS.c_concepto <= {#PARAMIN:@cod_hasta} %} {% %} %}
GROUP BY LIQ96_CONCEPTOS.c_concepto,liq99_liquidacion.e_periodo ORDER BY e_periodo asc
')/ROWS/ROW
